using System.Collections.Generic;
using BogDb.Core.Planner;
using BogDb.Core.Main;

namespace BogDb.Core.Optimizer;

/// <summary>
/// Manages execution over LogicalPlans by iterating rewriting constraints mapping optimization rules.
/// </summary>
public sealed class Optimizer
{
    private readonly List<LogicalRule> _rules;

    public Optimizer(BogDatabase database)
    {
        _rules = new List<LogicalRule>
        {
            // ── Correlated subquery unnesting (early, before join ordering) ────────
            new CorrelatedSubqueryUnnestRule(),

            // ── Cardinality and statistics ────────────────────────────────────────
            new CardinalityUpdater(database),

            // ── Filter / projection push-down ─────────────────────────────────────
            new FilterPushDownRule(),
            new ProjectionPushDownRule(),

            // ── Join ordering and cleanup ──────────────────────────────────────────
            new DPJoinEnumerator(),       // DP-based multi-way join enumeration (3+ operands)
            new JoinOrderOptimizer(),     // Greedy build-side swapping (2-way joins)
            new RemoveUnnecessaryJoinRule(),

            // ── Pipeline-breaker insertion (build-side accumulate) ─────────────────
            new AccHashJoinRule(),

            // ── Aggregate simplification ───────────────────────────────────────────
            new AggKeyDependencyRule(),

            // ── Factorization (no-op in BogDB flat-row model; C++ parity) ────────
            new FactorizationRewriterRule(),
            new RemoveFactorizationRewriterRule(),

            // ── LIMIT / TOP-K ─────────────────────────────────────────────────────
            new LimitPushDownRule(),
            new TopKOptimizerRule(),  // fuse ORDER BY + LIMIT → top-K heap

            // ── Schema annotation (idempotent, always last) ────────────────────────
            new SchemaPopulatorRule(),
        };
    }

    /// <summary>
    /// Executes heuristics sequentially tracking `changed` loop constraints until maximum execution boundaries are realized.
    /// </summary>
    public void Optimize(LogicalPlan plan)
    {
        bool changed;
        do
        {
            changed = false;
            foreach (var rule in _rules)
            {
                changed |= rule.Rewrite(plan);
                
                // In BogDb Native: We may fix root operator pointers if the rule moved the root node itself
                // (e.g. FilterPushDown swapping root PROJECTION and child FILTER).
                // Usually handled by reference context, but we will add logic later if needed.
            }
        } while (changed);
    }
}
